# Function to count high volatility days
def count_volatility_days(stock_data):
    if not stock_data:
        return 0
    count = 0
    for day in stock_data:
        try:
            high = float(day['High'])
            low = float(day['Low'])
            if low > 0:
                range_pct = (high - low) / low
                if range_pct > 0.20:
                    count += 1
        except (ValueError, TypeError):
            continue
    return count

